const { Manifold, CrossSection, Curves, label } = api;

// Create the basic tapered TV cabinet
const frontProfile = Curves.polyline([
  [-20, -15],
  [20, -15],
  [20, 15],
  [-20, 15]
], { fillet: 4 });

const backProfile = Curves.polyline([
  [-17, -13],
  [17, -13],
  [17, 13],
  [-17, 13]
], { fillet: 5 });

// Loft from back (-25) to front (0)
let body = Curves.loft([backProfile, frontProfile], [-25, 0]);

// Screen opening & control panel recesses (Z-aligned)
const screenProfile = Curves.polyline([
  [-17.5, -10],
  [6.5, -10],
  [6.5, 10],
  [-17.5, 10]
], { fillet: 3.5 });

const controlProfile = Curves.polyline([
  [9.5, -12],
  [16.5, -12],
  [16.5, 12],
  [9.5, 12]
], { fillet: 1.5 });

// Recess cutters
const screenRecess = screenProfile.extrude(3).translate([0, 0, -1.5]);
const controlRecess = controlProfile.extrude(3).translate([0, 0, -1.5]);

// Subtract recesses from main body
body = body.subtract(screenRecess).subtract(controlRecess);

// The cabinet shell is the warm retro-plastic body.
let cabinet = label(body, 'cabinet');

// CRT Screen Glass (bulging sphere) — the dark screen.
const screenCutter = screenProfile.extrude(10).translate([0, 0, -8]);
const screenSphere = Manifold.sphere(35).translate([-5.5, 0, -33.5]);
const screenGlass = label(screenCutter.intersect(screenSphere), 'screen');

// Assemble parts that will union into the cabinet.
let assembly = cabinet.add(screenGlass);

// Color-bar test pattern: thin blocks proud of the screen face.
// Screen recess front is near Z=0; bars sit at the screen center, just proud.
// Screen interior spans roughly X:[-17.5..6.5], Y:[-10..10].
const barColors = ['bar0', 'bar1', 'bar2', 'bar3', 'bar4', 'bar5'];
const barX0 = -16, barX1 = 5.5;      // horizontal span of bars
const barW = (barX1 - barX0) / barColors.length;
const barY0 = -8.5, barY1 = 8.5;     // vertical span
const barH = barY1 - barY0;
for (let i = 0; i < barColors.length; i++) {
  const cx = barX0 + barW * (i + 0.5);
  const bar = Manifold.cube([barW * 0.92, barH, 0.6], true)
    .translate([cx, (barY0 + barY1) / 2, 0.2]);
  assembly = assembly.add(label(bar, barColors[i]));
}

// Dials on control panel (starting at Z=-2 to ensure solid overlap)
const makeDial = (cx, cy) => {
  const baseDial = Manifold.cylinder(3, 2.2, 2.2).translate([cx, cy, -2]);
  const pointer = Manifold.cube([0.5, 2, 0.6]).translate([-0.25, 0, 2.5]).translate([cx, cy, -2]);
  return baseDial.add(pointer);
};

const dial1 = makeDial(13, 5);
const dial2 = makeDial(13, 0);

assembly = assembly.add(label(dial1, 'dials')).add(label(dial2, 'dials'));

// Speaker slots (subtract from control panel)
let speakerSlots = [];
for (let i = 0; i < 5; i++) {
  const y = -5 - i * 1.3;
  const slot = Manifold.cube([5, 0.5, 3], true).translate([13, y, -1]);
  speakerSlots.push(slot);
}
assembly = assembly.subtract(Manifold.compose(speakerSlots));

// Power button (starts at Z=-2 to overlap)
const powerButton = label(Manifold.cube([3, 1.5, 3], true).translate([13, -10, -0.5]), 'powerButton');
assembly = assembly.add(powerButton);

// Antenna base & rabbit ears (on top face Y = 15 at front, sloped to 13 at back)
const antennaBase = Manifold.sphere(2.5).translate([0, 13.5, -12.5]);

const makeAntenna = (angleZ, angleX) => {
  const rod = Manifold.cylinder(24, 0.4, 0.2);
  const tip = Manifold.sphere(0.8).translate([0, 0, 24]);
  return rod.add(tip)
    .rotate([-75, 0, angleZ])
    .translate([0, 13.5, -12.5]);
};

const antennaL = makeAntenna(30, 10);
const antennaR = makeAntenna(-30, 10);
// Dark antenna assembly (base + both rods).
const antenna = label(antennaBase.add(antennaL).add(antennaR), 'antenna');
assembly = assembly.add(antenna);

// Carrying handle on top
const path2D = Curves.arc({ from: [-6, 0], to: [6, 0], radius: 8 });
const path3D = path2D.map(p => [p[0], 14.0 + p[1], -8]);
const handleProfile = CrossSection.circle(1.0, 16);
const handle = label(Curves.sweep(handleProfile, path3D), 'handle');
assembly = assembly.add(handle);

// Squashed feet on bottom
const makeFoot = (cx, cz) => {
  const yBottom = -15 - 0.08 * cz;
  return Manifold.sphere(2.2).scale([1, 0.6, 1]).translate([cx, yBottom + 0.4, cz]);
};
const feet = [
  makeFoot(-14, -5),
  makeFoot(14, -5),
  makeFoot(-12, -20),
  makeFoot(12, -20)
];
assembly = assembly.add(label(Manifold.compose(feet), 'feet'));

// Vertical ventilation slots on the back face (Z = -25)
let ventSlots = [];
for (let i = -5; i <= 5; i++) {
  if (i === 0) continue;
  const x = i * 2.5;
  const slit = Manifold.cube([0.6, 12, 4], true).translate([x, 0, -24.5]);
  ventSlots.push(slit);
}
assembly = assembly.subtract(Manifold.compose(ventSlots));

// Rotate to final orientation: Y is depth, Z is height
assembly = assembly.rotate([90, 0, 0]);

return assembly;

